SUPPORTED_EXTENSIONS = {".txt", ".md", ".markdown", ".json", ".csv", ".html", ".htm"}


@dataclass
class DocumentChunk:
    id: str
    source: str
    chunk_index: int
    text: str
    metadata: Dict[str, Any]


class TextChunker:
    def __init__(self, chunk_size: int = 1200, chunk_overlap: int = 200):
        if chunk_overlap >= chunk_size:
            raise ValueError("chunk_overlap must be smaller than chunk_size")
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def chunk_text(self, text: str) -> List[str]:
        text = self._normalize_text(text)
        if not text:
            return []

        chunks = []
        start = 0
        n = len(text)

        while start < n:
            end = min(start + self.chunk_size, n)
            if end < n:
                split_at = text.rfind("\n", start, end)
                if split_at == -1 or split_at <= start + self.chunk_size // 2:
                    split_at = text.rfind(" ", start, end)
                if split_at != -1 and split_at > start:
                    end = split_at

            chunk = text[start:end].strip()
            if chunk:
                chunks.append(chunk)

            if end >= n:
                break

            start = max(end - self.chunk_overlap, start + 1)

        return chunks

    @staticmethod
    def _normalize_text(text: str) -> str:
        text = text.replace("\r\n", "\n").replace("\r", "\n")
        lines = [line.strip() for line in text.split("\n")]
        return "\n".join(lines).strip()


class FileLoader:
    @staticmethod
    def load_file(path: str) -> str:
        ext = os.path.splitext(path)[1].lower()
        if ext not in SUPPORTED_EXTENSIONS:
            return ""

        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            raw = f.read()

        if ext == ".json":
            try:
                parsed = json.loads(raw)
                return json.dumps(parsed, indent=2, ensure_ascii=False)
            except Exception:
                return raw

        if ext == ".csv":
            return raw

        if ext in {".html", ".htm"}:
            return FileLoader._strip_html(raw)

        return raw

    @staticmethod
    def load_directory(directory: str) -> List[Tuple[str, str]]:
        docs = []
        for root, _, files in os.walk(directory):
            for name in files:
                path = os.path.join(root, name)
                ext = os.path.splitext(path)[1].lower()
                if ext in SUPPORTED_EXTENSIONS:
                    content = FileLoader.load_file(path)
                    if content.strip():
                        docs.append((path, content))
        return docs

    @staticmethod
    def _strip_html(html: str) -> str:
        import re
        html = re.sub(r"(?is)<script.*?>.*?</script>", " ", html)
        html = re.sub(r"(?is)<style.*?>.*?</style>", " ", html)
        html = re.sub(r"(?s)<[^>]+>", " ", html)
        html = re.sub(r"\s+", " ", html)
        return html.strip()


class EmbeddingClient:
    def __init__(self, model: str = "text-embedding-3-small"):
        api_key = os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise ValueError("OPENAI_API_KEY is not set")
        self.client = OpenAI(api_key=api_key)
        self.model = model

    def embed_texts(self, texts: List[str]) -> List[List[float]]:
        if not texts:
            return []
        response = self.client.embeddings.create(model=self.model, input=texts)
        return [item.embedding for item in response.data]

    def embed_query(self, text: str) -> List[float]:
        response = self.client.embeddings.create(model=self.model, input=[text])
        return response.data[0].embedding


class VectorStore:
    def __init__(self, persist_dir: str = "./chroma_db", collection_name: str = "company_kb"):
        self.client = chromadb.PersistentClient(path=persist_dir)
        self.collection = self.client.get_or_create_collection(name=collection_name)

    def upsert_chunks(self, chunks: List[DocumentChunk], embeddings: List[List[float]]) -> None:
        if not chunks:
            return
        self.collection.upsert(
            ids=[c.id for c in chunks],
            documents=[c.text for c in chunks],
            metadatas=[c.metadata for c in chunks],
            embeddings=embeddings,
        )

    def query(self, embedding: List[float], top_k: int = 6) -> Dict[str, Any]:
        return self.collection.query(
            query_embeddings=[embedding],
            n_results=top_k,
            include=["documents", "metadatas", "distances"],
        )

    def count(self) -> int:
        return self.collection.count()


class RAGSystem:
    def __init__(
        self,
        persist_dir: str = "./chroma_db",
        collection_name: str = "company_kb",
        embedding_model: str = "text-embedding-3-small",
        llm_model: str = "gpt-4o-mini",
        chunk_size: int = 1200,
        chunk_overlap: int = 200,
    ):
        self.embedder = EmbeddingClient(model=embedding_model)
        self.store = VectorStore(persist_dir=persist_dir, collection_name=collection_name)
        self.chunker = TextChunker(chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        api_key = os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise ValueError("OPENAI_API_KEY is not set")
        self.llm = OpenAI(api_key=api_key)
        self.llm_model = llm_model

    def index_directory(self, directory: str, batch_size: int = 64) -> Dict[str, Any]:
        docs = FileLoader.load_directory(directory)
        all_chunks: List[DocumentChunk] = []

        for path, content in docs:
            pieces = self.chunker.chunk_text(content)
            for i, piece in enumerate(pieces):
                chunk = DocumentChunk(
                    id=str(uuid.uuid5(uuid.NAMESPACE_URL, f"{path}:{i}:{hash(piece)}")),
                    source=path,
                    chunk_index=i,
                    text=piece,
                    metadata={
                        "source": path,
                        "chunk_index": i,
                        "filename": os.path.basename(path),
                    },
                )
                all_chunks.append(chunk)

        total = len(all_chunks)
        for i in range(0, total, batch_size):
            batch = all_chunks[i:i + batch_size]
            embeddings = self.embedder.embed_texts([c.text for c in batch])
            self.store.upsert_chunks(batch, embeddings)

        return {
            "documents_found": len(docs),
            "chunks_indexed": total,
            "vector_count": self.store.count(),
        }

    def retrieve(self, query: str, top_k: int = 6) -> List[Dict[str, Any]]:
        query_embedding = self.embedder.embed_query(query)
        results = self.store.query(query_embedding, top_k=top_k)

        docs = results.get("documents", [[]])[0]
        metas = results.get("metadatas", [[]])[0]
        distances = results.get("distances", [[]])[0]

        retrieved = []
        for doc, meta, dist in zip(docs, metas, distances):
            retrieved.append({
                "text": doc,
                "metadata": meta,
                "distance": dist,
            })
        return retrieved

    def build_prompt(self, query: str, retrieved_docs: List[Dict[str, Any]]) -> str:
        context_blocks = []
        for i, item in enumerate(retrieved_docs, start=1):
            meta = item.get("metadata", {})
            source = meta.get("source", "unknown")
            chunk_index = meta.get("chunk_index", "unknown")
            text = item.get("text", "")
            context_blocks.append(
                f"[Document {i}]\n"
                f"Source: {source}\n"
                f"Chunk: {chunk_index}\n"
                f"Content:\n{text}"
            )

        context = "\n\n".join(context_blocks) if context_blocks else "No relevant documents found."

        return (
            "You are an internal company knowledge base assistant.\n"
            "Answer the user's question using the provided retrieved documents.\n"
            "If the answer is not contained in the documents, say you do not know based on the knowledge base.\n"
            "Cite relevant source file paths when helpful.\n\n"
            f"Retrieved Documents:\n{context}\n\n"
            f"User Question:\n{query}\n\n"
            "Answer:"
        )

    def answer(self, query: str, top_k: int = 6, temperature: float = 0.2) -> Dict[str, Any]:
        retrieved = self.retrieve(query=query, top_k=top_k)
        prompt = self.build_prompt(query=query, retrieved_docs=retrieved)

        response = self.llm.chat.completions.create(
            model=self.llm_model,
            temperature=temperature,
            messages=[
                {
                    "role": "system",
                    "content": "You answer questions for an internal company knowledge base chatbot."
                },
                {
                    "role": "user",
                    "content": prompt
                }
            ],
        )

        answer_text = response.choices[0].message.content
        return {
            "query": query,
            "answer": answer_text,
            "retrieved_documents": retrieved,
            "prompt": prompt,
        }


def main():
    parser = argparse.ArgumentParser(description="Python RAG system for internal knowledge base chatbot")
    subparsers = parser.add_subparsers(dest="command", required=True)

    index_parser = subparsers.add_parser("index", help="Index documents from a directory")
