    index_parser.add_argument("--collection", default="company_kb", help="Collection name")
    index_parser.add_argument("--embedding-model", default="text-embedding-3-small")
    index_parser.add_argument("--chunk-size", type=int, default=1200)
    index_parser.add_argument("--chunk-overlap", type=int, default=200)
    index_parser.add_argument("--batch-size", type=int, default=64)

    ask_parser = subparsers.add_parser("ask", help="Ask a question against the indexed knowledge base")
    ask_parser.add_argument("--query", required=True, help="User query")
    ask_parser.add_argument("--persist-dir", default="./chroma_db", help="Chroma persistence directory")
    ask_parser.add_argument("--collection", default="company_kb", help="Collection name")
    ask_parser.add_argument("--embedding-model", default="text-embedding-3-small")
